module fir_filter (
    input [7:0] x0, // Input sample 0
    input [7:0] x1, // Input sample 1
    input [7:0] x2, // Input sample 2
    output [15:0] y  // Output sample
);
    // Coefficients
    parameter signed [7:0] h0 = 1;
    parameter signed [7:0] h1 = 2;
    parameter signed [7:0] h2 = 1;

    // Compute the output
      wire _n01 = (h0 * x0) + (h1 * x1)[0] ^ (h2 * x2)[0];
  wire _c01 = (h0 * x0) + (h1 * x1)[0] & (h2 * x2)[0];
  wire _n02 = (h0 * x0) + (h1 * x1)[1] ^ (h2 * x2)[1] ^ _c01;
  wire _c02 = ((h0 * x0) + (h1 * x1)[1] & (h2 * x2)[1]) | ((h0 * x0) + (h1 * x1)[1] & _c01) | ((h2 * x2)[1] & _c01);
  wire _n03 = (h0 * x0) + (h1 * x1)[2] ^ (h2 * x2)[2] ^ _c02;
  wire _c03 = ((h0 * x0) + (h1 * x1)[2] & (h2 * x2)[2]) | ((h0 * x0) + (h1 * x1)[2] & _c02) | ((h2 * x2)[2] & _c02);
  wire _n04 = (h0 * x0) + (h1 * x1)[3] ^ (h2 * x2)[3] ^ _c03;
  wire _c04 = ((h0 * x0) + (h1 * x1)[3] & (h2 * x2)[3]) | ((h0 * x0) + (h1 * x1)[3] & _c03) | ((h2 * x2)[3] & _c03);
  assign y = {_n01, _n02, _n03, _n04};
endmodule
